ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?conference ?themetrack ?grade WHERE {
  ?a a :Theme_Tracks .
  ?b a :Submissions .
  ?b p:hasTheme_Tracks ?a .
  ?a p:conference ?conference .
  ?a p:themeTrack ?themetrack .
  ?b p:grade ?grade .
} }
  full: { SELECT ?conference ?themetrack ?submissiontopic ?grade WHERE {
  ?a a :Theme_Tracks .
  ?b a :Submissions .
  ?b p:hasTheme_Tracks ?a .
  ?a p:conference ?conference .
  ?a p:themeTrack ?themetrack .
  ?a p:submissionTopic ?submissiontopic .
  ?b p:grade ?grade .
} }
  component_2: { SELECT ?conference ?submissiontopic ?grade WHERE {
  ?a a :Theme_Tracks .
  ?b a :Submissions .
  ?b p:hasTheme_Tracks ?a .
  ?a p:conference ?conference .
  ?a p:submissionTopic ?submissiontopic .
  ?b p:grade ?grade .
} }
}
